33	//   - new on remote only → pull / mkdirLocal
34	//   - both new (conflict) → newer mtime wins; tie → local
35	//   - in base, local deleted, remote unchanged → deleteRemote
36	//   - in base, remote deleted, local unchanged → deleteLocal
37	//   - in base, local deleted, remote modified → pull (modification wins)
38	//   - in base, remote deleted, local modified → push (modification wins)
39	//   - in base, only local changed → push
40	//   - in base, only remote changed → pull
41	//   - in base, both changed (conflict) → newer mtime wins; tie → local
42	//   - in base, neither changed → in sync, no action
43	//
44	// Actions are returned sorted: mkdirs (shallow first), then push/pull,
45	// then deletes (deepest first).
46	func Plan(base map[string]BaseEntry, local, remote map[string]Entry) []Action {
