57		}
58	
59		var actions []Action
60	
61		for p := range paths {
62			b, hasBase := base[p]
63			l, hasLocal := local[p]
64			r, hasRemote := remote[p]
65	
66			localModified := hasLocal && hasBase && (l.Size != b.LSize || l.Mtime != b.LMtime)
67			remoteModified := hasRemote && hasBase && (r.Size != b.RSize || r.Mtime != b.RMtime)
68	
69			switch {
70			case !hasLocal && !hasRemote:
71				// Both absent (deleted on both sides, or already gone). Nothing to do.
72	
73			case hasLocal && !hasRemote && !hasBase:
74				// New on local only.
75				if l.IsDir {
76					actions = append(actions, Action{Op: OpMkdirRemote, Path: p, Reason: "new local dir"})
77				} else {
