99					} else {
100						actions = append(actions, Action{Op: OpPush, Path: p, Reason: "conflict: local newer or tie", Conflict: true})
101					}
102				} else {
103					// Remote wins.
104					if r.IsDir {
105						actions = append(actions, Action{Op: OpMkdirLocal, Path: p, Reason: "conflict: remote dir wins", Conflict: true})
106					} else {
107						actions = append(actions, Action{Op: OpPull, Path: p, Reason: "conflict: remote newer", Conflict: true})
108					}
109				}
110	
111			case !hasLocal && !hasRemote && hasBase:
112				// Both deleted since last sync — nothing to do.
113	
114			case !hasLocal && hasRemote && hasBase:
115				// Local was deleted since last sync.
116				if remoteModified {
117					// Remote was also modified — modification wins over deletion.
118					if r.IsDir {
119						actions = append(actions, Action{Op: OpMkdirLocal, Path: p, Reason: "modified remotely; local deleted"})
120					} else {
121						actions = append(actions, Action{Op: OpPull, Path: p, Reason: "modified remotely; local deleted"})
122					}
123				} else {
124					// Remote unchanged — propagate local deletion to remote.
125					if r.IsDir {
126						actions = append(actions, Action{Op: OpDeleteRemote, Path: p, Reason: "deleted locally (dir)"})
127					} else {
128						actions = append(actions, Action{Op: OpDeleteRemote, Path: p, Reason: "deleted locally"})
129					}
130				}
131	
132			case hasLocal && !hasRemote && hasBase:
133				// Remote was deleted since last sync.
134				if localModified {
135					// Local was also modified — modification wins over deletion.
136					if l.IsDir {
137						actions = append(actions, Action{Op: OpMkdirRemote, Path: p, Reason: "modified locally; remote deleted"})
138					} else {
139						actions = append(actions, Action{Op: OpPush, Path: p, Reason: "modified locally; remote deleted"})
140					}
141				} else {
142					// Local unchanged — propagate remote deletion to local.
143					if l.IsDir {
144						actions = append(actions, Action{Op: OpDeleteLocal, Path: p, Reason: "deleted remotely (dir)"})
145					} else {
146						actions = append(actions, Action{Op: OpDeleteLocal, Path: p, Reason: "deleted remotely"})
147					}
148				}
149	
150			case hasLocal && hasRemote && hasBase:
151				// Both present and in base.
152				switch {
153				case !localModified && !remoteModified:
154					// In sync — nothing to do.
155	
156				case localModified && !remoteModified:
157					// Only local changed.
158					if !l.IsDir {
159						actions = append(actions, Action{Op: OpPush, Path: p, Reason: "modified locally"})
160					}
161					// If it's a dir and it "changed" (mtime bump), no content action needed.
162	
163				case !localModified && remoteModified:
164					// Only remote changed.
165					if !r.IsDir {
166						actions = append(actions, Action{Op: OpPull, Path: p, Reason: "modified remotely"})
167					}
168	
169				default:
170					// Both changed — conflict.
171					if l.IsDir && r.IsDir {
172						break // Dir-vs-dir, no file content conflict.
173					}
174					if l.Mtime >= r.Mtime {
175						actions = append(actions, Action{Op: OpPush, Path: p, Reason: "conflict: local newer or tie", Conflict: true})
176					} else {
177						actions = append(actions, Action{Op: OpPull, Path: p, Reason: "conflict: remote newer", Conflict: true})
178					}
179				}
180			}
181		}
182	
183		return sortActions(actions)
184	}
185	
186	// sortActions orders actions so they can be applied safely:
187	//  1. mkdirLocal / mkdirRemote — shallowest first
188	//  2. push / pull
189	//  3. deleteLocal / deleteRemote — deepest first (so child files go before parent dirs)
190	func sortActions(actions []Action) []Action {
191		priority := func(op Op) int {
192			switch op {
193			case OpMkdirLocal, OpMkdirRemote:
194				return 0
195			case OpPush, OpPull:
196				return 1
197			default: // deleteLocal, deleteRemote
198				return 2
199			}
200		}
201	
202		sort.SliceStable(actions, func(i, j int) bool {
203			pi := priority(actions[i].Op)
204			pj := priority(actions[j].Op)
205			if pi != pj {
206				return pi < pj
207			}
208			di := strings.Count(actions[i].Path, "/")
209			dj := strings.Count(actions[j].Path, "/")
210			if pi == 0 {
211				// mkdirs: shallow first
212				if di != dj {
213					return di < dj
214				}
215			} else if pi == 2 {
216				// deletes: deepest first
217				if di != dj {
218					return di > dj
219				}
220			}
221			return actions[i].Path < actions[j].Path
222		})
223	
224		return actions
225	}
