20		transportLocal               // local:<abs-path> — no ssh, direct FS ops
21	)
22	
23	// RemoteConn describes and operates on one side of a sync pair.
24	type RemoteConn struct {
25		Kind    transportKind
26		Host    string // SSH: user@host; Local: ""
27		Root    string // absolute-ish remote root path (may start with ~)
28	}
