30	// ParseRemote parses a remote spec into a RemoteConn.
31	//
32	//   - "local:<abs-path>"  → local transport, useful for mounted volumes and tests
33	//   - "user@host:path"    → SSH transport
34	func ParseRemote(spec string) (*RemoteConn, error) {
35		if strings.HasPrefix(spec, "local:") {
36			root := spec[len("local:"):]
37			if root == "" {
38				return nil, fmt.Errorf("remote spec %q: local: requires a path", spec)
39			}
40			return &RemoteConn{Kind: transportLocal, Root: root}, nil
41		}
42	
43		// Expect user@host:path or host:path
44		idx := strings.LastIndex(spec, ":")
45		if idx < 0 {
46			return nil, fmt.Errorf("remote spec %q: expected user@host:path or local:<path>", spec)
47		}
48		host := spec[:idx]
49		path := spec[idx+1:]
50		if host == "" || path == "" {
51			return nil, fmt.Errorf("remote spec %q: host and path must be non-empty", spec)
52		}
53		return &RemoteConn{Kind: transportSSH, Host: host, Root: path}, nil
54	}
