56	// --- Scan ---
57	
58	// Scan returns an Entry map for the remote root, applying excludes.
59	// For SSH transport it invokes `caravan scan --json` on the remote; on scan
60	// failure that looks like a missing binary it attempts to bootstrap the remote
61	// and retries once.
62	func (r *RemoteConn) Scan(excludes []string) (map[string]Entry, error) {
63		switch r.Kind {
64		case transportLocal:
65			return r.scanLocal(excludes)
66		case transportSSH:
67			return r.scanSSH(excludes, true)
68		}
69		return nil, fmt.Errorf("unknown transport kind %d", r.Kind)
70	}
