72	func (r *RemoteConn) scanLocal(excludes []string) (map[string]Entry, error) {
73		if err := os.MkdirAll(r.Root, 0o755); err != nil {
74			return nil, fmt.Errorf("local remote mkdir %s: %w", r.Root, err)
75		}
76		entries, _, err := ScanDir(r.Root, excludes)
77		return entries, err
78	}
79	
80	func (r *RemoteConn) scanSSH(excludes []string, allowBootstrap bool) (map[string]Entry, error) {
81		excArg := strings.Join(excludes, ",")
82		remotePath := shellRemotePath(r.Root)
83		var cmd string
84		if excArg != "" {
85			cmd = fmt.Sprintf(`~/.local/bin/caravan scan --json %s --exclude %q`, remotePath, excArg)
86		} else {
87			cmd = fmt.Sprintf(`~/.local/bin/caravan scan --json %s`, remotePath)
88		}
89	
90		out, err := exec.Command("ssh", "-o", "BatchMode=yes", r.Host, cmd).Output()
91		if err != nil {
92			if allowBootstrap && looksLikeMissingBinary(err, out) {
93				fmt.Fprintf(os.Stderr, "caravan: remote binary not found on %s; bootstrapping…\n", r.Host)
94				if berr := r.bootstrap(); berr != nil {
95					return nil, fmt.Errorf("bootstrap %s: %w", r.Host, berr)
96				}
97				// Also ensure the remote root exists.
98				_ = r.mkdirSSH("")
99				return r.scanSSH(excludes, false)
100			}
101			// Try to create the remote root if it doesn't exist and retry once.
102			if allowBootstrap && looksLikeMissingDir(err, out) {
103				_ = r.mkdirSSH("")
104				return r.scanSSH(excludes, false)
105			}
106			return nil, fmt.Errorf("remote scan on %s: %w", r.Host, err)
107		}
108	
109		var result ScanResult
110		if err := json.Unmarshal(out, &result); err != nil {
111			return nil, fmt.Errorf("parse remote scan: %w", err)
112		}
113		if result.Entries == nil {
114			result.Entries = map[string]Entry{}
115		}
116		return result.Entries, nil
117	}
118	
119	func looksLikeMissingBinary(err error, out []byte) bool {
120		if ee, ok := err.(*exec.ExitError); ok {
121			if ee.ExitCode() == 127 {
122				return true
123			}
124			combined := strings.ToLower(string(ee.Stderr) + string(out))
125			return strings.Contains(combined, "not found") || strings.Contains(combined, "no such file")
126		}
127		return false
128	}
129	
130	func looksLikeMissingDir(err error, _ []byte) bool {
131		if ee, ok := err.(*exec.ExitError); ok {
132			combined := strings.ToLower(string(ee.Stderr))
133			return strings.Contains(combined, "no such file") || strings.Contains(combined, "not a directory") || ee.ExitCode() == 1
134		}
135		return false
136	}
137	
138	// bootstrap copies the current executable to ~/.local/bin/caravan on the remote.
139	func (r *RemoteConn) bootstrap() error {
140		// Verify architecture matches.
141		uname, err := exec.Command("ssh", "-o", "BatchMode=yes", r.Host, "uname -sm").Output()
142		if err != nil {
143			return fmt.Errorf("uname check: %w", err)
144		}
145		localPlatform := localUnameSM()
146		remotePlatform := strings.TrimSpace(string(uname))
147		if !strings.EqualFold(localPlatform, remotePlatform) {
148			return fmt.Errorf("platform mismatch: local=%q remote=%q; cannot bootstrap", localPlatform, remotePlatform)
149		}
150	
151		exe, err := os.Executable()
152		if err != nil {
153			return fmt.Errorf("resolve executable: %w", err)
154		}
155		exeFile, err := os.Open(exe)
156		if err != nil {
157			return fmt.Errorf("open executable: %w", err)
158		}
159		defer exeFile.Close()
160	
161		install := exec.Command("ssh", "-o", "BatchMode=yes", r.Host,
162			`mkdir -p ~/.local/bin && cat > ~/.local/bin/caravan && chmod +x ~/.local/bin/caravan`)
163		install.Stdin = exeFile
164		install.Stderr = os.Stderr
165		if err := install.Run(); err != nil {
166			return fmt.Errorf("install binary: %w", err)
167		}
168		fmt.Fprintf(os.Stderr, "caravan: bootstrapped remote binary on %s\n", r.Host)
169		return nil
170	}
171	
172	func localUnameSM() string {
173		goos := runtime.GOOS
174		arch := runtime.GOARCH
175		// Map Go GOOS/GOARCH → uname -sm output (e.g. "Darwin arm64").
176		osMap := map[string]string{
177			"darwin":  "Darwin",
178			"linux":   "Linux",
179			"freebsd": "FreeBSD",
180		}
181		archMap := map[string]string{
182			"amd64": "x86_64",
183			"arm64": "arm64",
184			"386":   "i386",
185		}
186		uname := goos
187		if v, ok := osMap[goos]; ok {
188			uname = v
189		}
190		a := arch
191		if v, ok := archMap[arch]; ok {
192			a = v
193		}
194		return uname + " " + a
195	}
196	
197	// shellRemotePath converts a remote path so it is safe inside a double-quoted
198	// shell argument while still allowing $HOME expansion.
199	// "~/foo" → "$HOME/foo"; "/abs" → "/abs" (unquoted later by caller wrapping in "…").
200	func shellRemotePath(p string) string {
201		if p == "~" {
202			return `"$HOME"`
203		}
204		if strings.HasPrefix(p, "~/") {
205			return `"$HOME/` + p[2:] + `"`
206		}
207		return `"` + p + `"`
208	}
209	
210	// absoluteRemotePath replaces the ~ prefix with $HOME for shell-expanded contexts.
211	func absoluteRemotePath(root, rel string) string {
212		base := root
213		if rel != "" && rel != "." {
214			base = root + "/" + rel
215		}
216		return base
217	}
218	
219	// --- Mkdir ---
220	
221	// MkdirAll creates a directory (and parents) under the remote root.
222	// rel="" creates the root itself.
223	func (r *RemoteConn) MkdirAll(rel string) error {
224		switch r.Kind {
225		case transportLocal:
226			target := r.Root
227			if rel != "" {
228				target = filepath.Join(r.Root, filepath.FromSlash(rel))
229			}
230			return os.MkdirAll(target, 0o755)
231		case transportSSH:
232			return r.mkdirSSH(rel)
233		}
234		return nil
235	}
236	
237	func (r *RemoteConn) mkdirSSH(rel string) error {
238		target := absoluteRemotePath(r.Root, rel)
239		cmd := fmt.Sprintf("mkdir -p %s", shellRemotePath(target))
240		return exec.Command("ssh", "-o", "BatchMode=yes", r.Host, cmd).Run()
241	}
242	
243	// --- Push (local → remote) ---
244	
245	// Push copies files from localRoot to the remote root using tar (SSH) or
246	// direct file copies (local:).  paths is relative to both roots.
247	func (r *RemoteConn) Push(localRoot string, paths []string) error {
248		if len(paths) == 0 {
249			return nil
250		}
251		switch r.Kind {
252		case transportLocal:
253			return r.pushLocal(localRoot, paths)
254		case transportSSH:
255			return r.pushSSH(localRoot, paths)
256		}
257		return nil
258	}
259	
260	func (r *RemoteConn) pushLocal(localRoot string, paths []string) error {
261		for _, p := range paths {
262			src := filepath.Join(localRoot, filepath.FromSlash(p))
263			dst := filepath.Join(r.Root, filepath.FromSlash(p))
264			if err := os.MkdirAll(filepath.Dir(dst), 0o755); err != nil {
265				return err
266			}
267			if err := copyFile(src, dst); err != nil {
268				return fmt.Errorf("push %s: %w", p, err)
269			}
270		}
271		return nil
272	}
273	
274	func (r *RemoteConn) pushSSH(localRoot string, paths []string) error {
275		// Write the file list to a temp file.
276		tmpList, err := os.CreateTemp("", "caravan-push-*")
277		if err != nil {
278			return err
279		}
280		defer os.Remove(tmpList.Name())
281		for _, p := range paths {
282			if _, err := fmt.Fprintln(tmpList, p); err != nil {
283				tmpList.Close()
284				return err
285			}
286		}
287		if err := tmpList.Close(); err != nil {
288			return err
289		}
290	
291		remoteRoot := shellRemotePath(r.Root)
292		sshScript := fmt.Sprintf(`mkdir -p %s && tar -C %s -xpf -`, remoteRoot, remoteRoot)
293	
294		tarCmd := exec.Command("tar", "-C", localRoot, "-cf", "-", "-T", tmpList.Name())
295		sshCmd := exec.Command("ssh", "-o", "BatchMode=yes", r.Host, sshScript)
296	
297		pr, pw := io.Pipe()
298		tarCmd.Stdout = pw
299		tarCmd.Stderr = os.Stderr
300		sshCmd.Stdin = pr
301		sshCmd.Stderr = os.Stderr
302	
303		if err := sshCmd.Start(); err != nil {
304			pw.Close()
305			return fmt.Errorf("ssh push: start ssh: %w", err)
306		}
307		if err := tarCmd.Start(); err != nil {
308			pw.CloseWithError(err)
309			sshCmd.Wait() //nolint
310			return fmt.Errorf("ssh push: start tar: %w", err)
311		}
312	
313		var tarErr error
314		var wg sync.WaitGroup
315		wg.Add(1)
316		go func() {
317			defer wg.Done()
318			defer pw.Close()
319			tarErr = tarCmd.Wait()
320		}()
321	
322		sshErr := sshCmd.Wait()
323		wg.Wait()
324	
325		if tarErr != nil {
326			return fmt.Errorf("ssh push tar: %w", tarErr)
327		}
328		if sshErr != nil {
329			return fmt.Errorf("ssh push: %w", sshErr)
330		}
331		return nil
332	}
333	
334	// --- Pull (remote → local) ---
335	
336	// Pull fetches files from the remote root to localRoot.
337	func (r *RemoteConn) Pull(localRoot string, paths []string) error {
338		if len(paths) == 0 {
339			return nil
340		}
341		switch r.Kind {
342		case transportLocal:
343			return r.pullLocal(localRoot, paths)
344		case transportSSH:
345			return r.pullSSH(localRoot, paths)
346		}
347		return nil
348	}
349	
350	func (r *RemoteConn) pullLocal(localRoot string, paths []string) error {
351		for _, p := range paths {
352			src := filepath.Join(r.Root, filepath.FromSlash(p))
353			dst := filepath.Join(localRoot, filepath.FromSlash(p))
354			if err := os.MkdirAll(filepath.Dir(dst), 0o755); err != nil {
355				return err
356			}
357			if err := copyFile(src, dst); err != nil {
358				return fmt.Errorf("pull %s: %w", p, err)
359			}
360		}
361		return nil
362	}
363	
364	func (r *RemoteConn) pullSSH(localRoot string, paths []string) error {
365		listData := strings.Join(paths, "\n") + "\n"
366		remoteRoot := shellRemotePath(r.Root)
367		sshScript := fmt.Sprintf(
368			`cd %s && cat > /tmp/caravan-list-%d && tar -cf - -T /tmp/caravan-list-%d && rm -f /tmp/caravan-list-%d`,
369			remoteRoot, os.Getpid(), os.Getpid(), os.Getpid(),
370		)
371	
372		sshCmd := exec.Command("ssh", "-o", "BatchMode=yes", r.Host, sshScript)
373		sshCmd.Stdin = strings.NewReader(listData)
374		sshCmd.Stderr = os.Stderr
375	
376		tarCmd := exec.Command("tar", "-C", localRoot, "-xpf", "-")
377		tarCmd.Stderr = os.Stderr
378	
379		pr, pw := io.Pipe()
380		sshCmd.Stdout = pw
381		tarCmd.Stdin = pr
382	
383		if err := tarCmd.Start(); err != nil {
384			return fmt.Errorf("ssh pull: start tar: %w", err)
385		}
386	
387		var sshErr error
388		var wg sync.WaitGroup
389		wg.Add(1)
390		go func() {
391			defer wg.Done()
392			defer pw.Close()
393			sshErr = sshCmd.Run()
394		}()
395	
396		tarErr := tarCmd.Wait()
397		wg.Wait()
398	
399		if tarErr != nil {
400			return fmt.Errorf("ssh pull tar: %w", tarErr)
401		}
402		if sshErr != nil {
403			return fmt.Errorf("ssh pull: %w", sshErr)
404		}
405		return nil
406	}
407	
408	// --- Delete ---
409	
410	// DeleteFiles removes files (not dirs) under the remote root.
411	func (r *RemoteConn) DeleteFiles(paths []string) error {
412		if len(paths) == 0 {
413			return nil
414		}
415		switch r.Kind {
416		case transportLocal:
417			for _, p := range paths {
418				if err := os.Remove(filepath.Join(r.Root, filepath.FromSlash(p))); err != nil && !os.IsNotExist(err) {
419					return err
420				}
421			}
422			return nil
423		case transportSSH:
424			return r.deleteSSH(paths, false)
425		}
426		return nil
427	}
428	
429	// DeleteDir removes a directory (recursively) under the remote root.
430	func (r *RemoteConn) DeleteDir(path string) error {
431		switch r.Kind {
432		case transportLocal:
433			return os.RemoveAll(filepath.Join(r.Root, filepath.FromSlash(path)))
434		case transportSSH:
435			return r.deleteSSH([]string{path}, true)
436		}
437		return nil
438	}
439	
440	func (r *RemoteConn) deleteSSH(paths []string, recursive bool) error {
441		var args []string
442		if recursive {
443			args = append(args, "-rf")
444		}
445		// Paths must not contain single quotes (guaranteed by ScanDir skip).
446		for _, p := range paths {
447			abs := absoluteRemotePath(r.Root, p)
448			if strings.HasPrefix(abs, "~/") {
449				abs = `"$HOME/` + abs[2:] + `"`
450			} else if abs == "~" {
451				abs = `"$HOME"`
452			} else {
453				abs = `'` + abs + `'`
454			}
455			args = append(args, abs)
456		}
457		cmd := "rm " + strings.Join(args, " ")
458		return exec.Command("ssh", "-o", "BatchMode=yes", r.Host, cmd).Run()
459	}
460	
461	// --- Helpers ---
462	
463	// copyFile copies src to dst, preserving mtime.
464	func copyFile(src, dst string) error {
465		in, err := os.Open(src)
466		if err != nil {
467			return err
468		}
469		defer in.Close()
470	
471		info, err := in.Stat()
472		if err != nil {
473			return err
474		}
475	
476		out, err := os.OpenFile(dst, os.O_WRONLY|os.O_CREATE|os.O_TRUNC, info.Mode())
477		if err != nil {
478			return err
479		}
480	
481		if _, err := io.Copy(out, in); err != nil {
482			out.Close()
483			return err
484		}
485		if err := out.Close(); err != nil {
486			return err
487		}
488	
489		// Preserve mtime.
490		return os.Chtimes(dst, info.ModTime(), info.ModTime())
491	}
492

