14	
15	// SyncStats summarises what happened during one sync run.
16	type SyncStats struct {
17		Pushed    int
18		Pulled    int
19		DeletedL  int // local deletions
20		DeletedR  int // remote deletions
21		Conflicts int
22		Errors    int
23	}
24	
25	// CmdSync implements `caravan sync [NAME] [--watch] [--interval 2s] [--dry-run] [--bootstrap] [-f manifest]`.
26	func CmdSync(args []string) int {
27		fs := flag.NewFlagSet("sync", flag.ContinueOnError)
28		fs.SetOutput(os.Stderr)
29		manifestPath := fs.String("f", "", "manifest path")
30		dryRun := fs.Bool("dry-run", false, "print plan without applying")
31		watch := fs.Bool("watch", false, "loop continuously")
32		intervalStr := fs.String("interval", "2s", "watch interval (e.g. 2s)")
33		_ = fs.Bool("bootstrap", false, "bootstrap remote binary (always attempted automatically)")
34	
35		if err := fs.Parse(args); err != nil {
36			return 2
37		}
38	
39		interval, err := time.ParseDuration(*intervalStr)
40		if err != nil {
41			fmt.Fprintf(os.Stderr, "sync: invalid --interval %q: %v\n", *intervalStr, err)
42			return 2
43		}
44	
45		mpath := manifest.ResolvePath(*manifestPath)
46		m, err := manifest.Load(mpath)
47		if err != nil {
48			fmt.Fprintf(os.Stderr, "sync: %v\n", err)
49			return 1
50		}
51	
52		if len(m.Sync) == 0 {
53			fmt.Fprintln(os.Stderr, "sync: no [[sync]] entries in manifest")
54			return 1
55		}
56	
57		// Determine which sync entries to process.
58		var entries []manifest.Sync
59		if fs.NArg() == 0 {
60			entries = m.Sync
61		} else {
62			name := fs.Arg(0)
63			for _, s := range m.Sync {
64				if s.Name == name {
65					entries = append(entries, s)
66					break
67				}
68			}
69			if len(entries) == 0 {
70				fmt.Fprintf(os.Stderr, "sync: no sync entry named %q\n", name)
71				return 1
72			}
73		}
74	
75		if !*watch {
76			code := 0
77			for _, s := range entries {
78				if err := runSyncEntry(s, *dryRun); err != nil {
79					fmt.Fprintf(os.Stderr, "sync %s: %v\n", s.Name, err)
80					code = 1
81				}
82			}
83			return code
84		}
85	
86		// Watch mode.
87		sigCh := make(chan os.Signal, 1)
88		signal.Notify(sigCh, syscall.SIGINT, syscall.SIGTERM)
89		defer signal.Stop(sigCh)
90	
91		names := make([]string, len(entries))
92		for i, s := range entries {
93			names[i] = s.Name
94		}
95		fmt.Printf("watching %s (interval %s)\n", strings.Join(names, ", "), interval)
96	
97		ticker := time.NewTicker(interval)
98		defer ticker.Stop()
99	
100		for {
101			select {
102			case <-sigCh:
103				return 0
104			case <-ticker.C:
105				for _, s := range entries {
106					if err := runSyncEntry(s, *dryRun); err != nil {
107						fmt.Fprintf(os.Stderr, "sync %s: %v\n", s.Name, err)
108					}
109				}
110			}
111		}
112	}
113	
114	// runSyncEntry runs one sync pass for a single [[sync]] entry.
115	func runSyncEntry(s manifest.Sync, dryRun bool) error {
116		localRoot := manifest.ExpandPath(s.Local)
117		if err := os.MkdirAll(localRoot, 0o755); err != nil {
118			return fmt.Errorf("mkdir local %s: %w", localRoot, err)
119		}
120	
121		remote, err := ParseRemote(s.Remote)
122		if err != nil {
123			return err
124		}
125	
126		excludes := s.Excludes()
127	
128		// Scan local.
129		localEntries, _, err := ScanDir(localRoot, excludes)
130		if err != nil {
131			return fmt.Errorf("local scan: %w", err)
132		}
133	
134		// Scan remote (creates remote root if needed).
135		remoteEntries, err := remote.Scan(excludes)
136		if err != nil {
137			return fmt.Errorf("remote scan: %w", err)
138		}
139	
140		// Load base snapshot.
141		state, err := LoadState(s.Name)
142		if err != nil {
143			return fmt.Errorf("load state: %w", err)
144		}
145	
146		// Plan.
147		actions := Plan(state.Pairs, localEntries, remoteEntries)
148	
149		if len(actions) == 0 {
150			total := countFiles(localEntries)
151			fmt.Printf("✓ %s in sync (%d files)\n", s.Name, total)
152			return nil
153		}
154	
155		// Print plan.
156		printPlan(s.Name, actions)
157	
158		if dryRun {
159			return nil
160		}
161	
162		// Apply.
163		stats, applyErr := applyActions(actions, localRoot, remote, localEntries, remoteEntries)
164	
165		// Rescan both sides to build the new authoritative base.
166		newLocal, _, _ := ScanDir(localRoot, excludes)
167		newRemote, _ := remote.Scan(excludes)
168		newBase := buildBase(newLocal, newRemote)
169	
170		newState := &State{
171			Pairs:    newBase,
172			LastSync: time.Now().UnixNano(),
173		}
174		if err := SaveState(s.Name, newState); err != nil {
175			fmt.Fprintf(os.Stderr, "sync: save state: %v\n", err)
176		}
177	
178		// Summary line.
179		fmt.Printf("  pushed %d, pulled %d, deleted %d local/%d remote, conflicts %d",
180			stats.Pushed, stats.Pulled, stats.DeletedL, stats.DeletedR, stats.Conflicts)
181		if stats.Errors > 0 {
182			fmt.Printf(", errors %d", stats.Errors)
183		}
184		fmt.Println()
185	
186		return applyErr
187	}
188	
189	// applyActions executes the plan.
190	func applyActions(
191		actions []Action,
192		localRoot string,
193		remote *RemoteConn,
194		localEntries, remoteEntries map[string]Entry,
195	) (SyncStats, error) {
196		var stats SyncStats
197		var pushPaths, pullPaths []string
198		var delLocalFiles, delRemoteFiles, delLocalDirs, delRemoteDirs []string
199	
200		for _, a := range actions {
201			if a.Conflict {
202				winner := "local"
203				if a.Op == OpPull {
204					winner = "remote"
205				}
206				fmt.Printf("  conflict: %s (%s wins)\n", a.Path, winner)
207				stats.Conflicts++
208			}
209	
210			switch a.Op {
211			case OpMkdirLocal:
212				if err := os.MkdirAll(localJoin(localRoot, a.Path), 0o755); err != nil {
213					fmt.Fprintf(os.Stderr, "mkdir local %s: %v\n", a.Path, err)
214					stats.Errors++
215				}
216			case OpMkdirRemote:
217				if err := remote.MkdirAll(a.Path); err != nil {
218					fmt.Fprintf(os.Stderr, "mkdir remote %s: %v\n", a.Path, err)
219					stats.Errors++
220				}
221			case OpPush:
222				pushPaths = append(pushPaths, a.Path)
223			case OpPull:
224				pullPaths = append(pullPaths, a.Path)
225			case OpDeleteLocal:
226				if e, ok := localEntries[a.Path]; ok && e.IsDir {
227					delLocalDirs = append(delLocalDirs, a.Path)
228				} else {
229					delLocalFiles = append(delLocalFiles, a.Path)
230				}
231			case OpDeleteRemote:
232				if e, ok := remoteEntries[a.Path]; ok && e.IsDir {
233					delRemoteDirs = append(delRemoteDirs, a.Path)
234				} else {
235					delRemoteFiles = append(delRemoteFiles, a.Path)
236				}
237			}
238		}
239	
240		// Push files.
241		if len(pushPaths) > 0 {
242			if err := remote.Push(localRoot, pushPaths); err != nil {
243				fmt.Fprintf(os.Stderr, "push: %v\n", err)
244				stats.Errors++
245			} else {
246				stats.Pushed += len(pushPaths)
247			}
248		}
249	
250		// Pull files.
251		if len(pullPaths) > 0 {
252			if err := remote.Pull(localRoot, pullPaths); err != nil {
253				fmt.Fprintf(os.Stderr, "pull: %v\n", err)
254				stats.Errors++
255			} else {
256				stats.Pulled += len(pullPaths)
257			}
258		}
259	
260		// Delete local files.
261		for _, p := range delLocalFiles {
262			if err := os.Remove(localJoin(localRoot, p)); err != nil && !os.IsNotExist(err) {
263				fmt.Fprintf(os.Stderr, "delete local %s: %v\n", p, err)
264				stats.Errors++
265			} else {
266				stats.DeletedL++
267			}
268		}
269	
270		// Delete remote files.
271		if len(delRemoteFiles) > 0 {
272			if err := remote.DeleteFiles(delRemoteFiles); err != nil {
273				fmt.Fprintf(os.Stderr, "delete remote files: %v\n", err)
274				stats.Errors++
275			} else {
276				stats.DeletedR += len(delRemoteFiles)
277			}
278		}
279	
280		// Delete local dirs (deepest first — already sorted by planner).
281		for _, p := range delLocalDirs {
282			if err := os.RemoveAll(localJoin(localRoot, p)); err != nil {
283				fmt.Fprintf(os.Stderr, "delete local dir %s: %v\n", p, err)
284				stats.Errors++
285			} else {
286				stats.DeletedL++
287			}
288		}
289	
290		// Delete remote dirs (deepest first — already sorted by planner).
291		for _, p := range delRemoteDirs {
292			if err := remote.DeleteDir(p); err != nil {
293				fmt.Fprintf(os.Stderr, "delete remote dir %s: %v\n", p, err)
294				stats.Errors++
295			} else {
296				stats.DeletedR++
297			}
298		}
299	
300		return stats, nil
301	}
302	
303	// buildBase constructs a new base from the intersection of post-apply local and
304	// remote scans.  Only paths present on BOTH sides are recorded; a path missing
305	// on one side means the transfer failed and should be retried next run.
306	func buildBase(local, remote map[string]Entry) map[string]BaseEntry {
