			if err := remote.MkdirAll(a.Path); err != nil {
				fmt.Fprintf(os.Stderr, "mkdir remote %s: %v\n", a.Path, err)
				stats.Errors++
			}
		case OpPush:
			pushPaths = append(pushPaths, a.Path)
		case OpPull:
