17	// transportKind identifies the transfer mechanism.
18	type transportKind int
19	
20	const (
21		transportSSH   transportKind = iota
22		transportLocal               // local:<abs-path> — no ssh, direct FS ops
23	)
24	
25	// RemoteConn describes and operates on one side of a sync pair.
26	type RemoteConn struct {
27		Kind    transportKind
28		Host    string // SSH: user@host; Local: ""
29		Root    string // absolute-ish remote root path (may start with ~)
30	}
31	
32	// ParseRemote parses a remote spec into a RemoteConn.
33	//
34	//   - "local:<abs-path>"  → local transport, useful for mounted volumes and tests
35	//   - "user@host:path"    → SSH transport
36	func ParseRemote(spec string) (*RemoteConn, error) {
37		if strings.HasPrefix(spec, "local:") {
38			root := spec[len("local:"):]
39			if root == "" {
40				return nil, fmt.Errorf("remote spec %q: local: requires a path", spec)
41			}
42			return &RemoteConn{Kind: transportLocal, Root: root}, nil
43		}
44	
45		// Expect user@host:path or host:path
46		idx := strings.LastIndex(spec, ":")
47		if idx < 0 {
48			return nil, fmt.Errorf("remote spec %q: expected user@host:path or local:<path>", spec)
49		}
50		host := spec[:idx]
51		path := spec[idx+1:]
52		if host == "" || path == "" {
53			return nil, fmt.Errorf("remote spec %q: host and path must be non-empty", spec)
54		}
55		return &RemoteConn{Kind: transportSSH, Host: host, Root: path}, nil
56	}
