58	// --- Scan ---
59	
60	// Scan returns an Entry map for the remote root, applying excludes.
61	// For SSH transport it invokes `caravan scan --json` on the remote; on scan
62	// failure that looks like a missing binary it attempts to bootstrap the remote
63	// and retries once.
64	func (r *RemoteConn) Scan(excludes []string) (map[string]Entry, error) {
65		switch r.Kind {
66		case transportLocal:
67			return r.scanLocal(excludes)
68		case transportSSH:
69			return r.scanSSH(excludes, true)
70		}
71		return nil, fmt.Errorf("unknown transport kind %d", r.Kind)
72	}
