74	func (r *RemoteConn) scanLocal(excludes []string) (map[string]Entry, error) {
75		if err := os.MkdirAll(r.Root, 0o755); err != nil {
76			return nil, fmt.Errorf("local remote mkdir %s: %w", r.Root, err)
77		}
78		entries, _, err := ScanDir(r.Root, excludes)
