92		out, err := exec.Command("ssh", "-o", "BatchMode=yes", r.Host, cmd).Output()
93		if err != nil {
94			if allowBootstrap && looksLikeMissingBinary(err, out) {
95				fmt.Fprintf(os.Stderr, "caravan: remote binary not found on %s; bootstrapping…\n", r.Host)
96				if berr := r.bootstrap(); berr != nil {
