160	// bootstrap copies the current executable to ~/.local/bin/caravan on the remote.
161	func (r *RemoteConn) bootstrap() error {
162		// Verify architecture matches.
163		uname, err := exec.Command("ssh", "-o", "BatchMode=yes", r.Host, "uname -sm").Output()
164		if err != nil {
165			return fmt.Errorf("uname check: %w", err)
166		}
167		localPlatform := localUnameSM()
168		remotePlatform := strings.TrimSpace(string(uname))
169		if !strings.EqualFold(localPlatform, remotePlatform) {
170			return fmt.Errorf("platform mismatch: local=%q remote=%q; cannot bootstrap", localPlatform, remotePlatform)
171		}
172	
173		exe, err := os.Executable()
174		if err != nil {
175			return fmt.Errorf("resolve executable: %w", err)
176		}
177		exeFile, err := os.Open(exe)
178		if err != nil {
179			return fmt.Errorf("open executable: %w", err)
180		}
181		defer exeFile.Close()
182	
183		install := exec.Command("ssh", "-o", "BatchMode=yes", r.Host,
184			`mkdir -p ~/.local/bin && cat > ~/.local/bin/caravan && chmod +x ~/.local/bin/caravan`)
185		install.Stdin = exeFile
186		install.Stderr = os.Stderr
187		if err := install.Run(); err != nil {
188			return fmt.Errorf("install binary: %w", err)
189		}
190		fmt.Fprintf(os.Stderr, "caravan: bootstrapped remote binary on %s\n", r.Host)
191		return nil
192	}
