194	func localUnameSM() string {
195		goos := runtime.GOOS
196		arch := runtime.GOARCH
197		// Map Go GOOS/GOARCH → uname -sm output (e.g. "Darwin arm64").
198		osMap := map[string]string{
199			"darwin":  "Darwin",
200			"linux":   "Linux",
201			"freebsd": "FreeBSD",
202		}
203		archMap := map[string]string{
204			"amd64": "x86_64",
205			"arm64": "arm64",
206			"386":   "i386",
207		}
208		uname := goos
209		if v, ok := osMap[goos]; ok {
210			uname = v
211		}
212		a := arch
213		if v, ok := archMap[arch]; ok {
214			a = v
215		}
216		return uname + " " + a
217	}
