219	// shellRemotePath converts a remote path so it is safe inside a double-quoted
220	// shell argument while still allowing $HOME expansion.
221	// "~/foo" → "$HOME/foo"; "/abs" → "/abs" (unquoted later by caller wrapping in "…").
222	func shellRemotePath(p string) string {
223		if p == "~" {
224			return `"$HOME"`
225		}
226		if strings.HasPrefix(p, "~/") {
227			return `"$HOME/` + p[2:] + `"`
228		}
229		return `"` + p + `"`
230	}
