232	// absoluteRemotePath replaces the ~ prefix with $HOME for shell-expanded contexts.
233	func absoluteRemotePath(root, rel string) string {
234		base := root
235		if rel != "" && rel != "." {
236			base = root + "/" + rel
237		}
238		return base
239	}
