  (cd "$LOCAL_DIR" && find . -type f ! -name .DS_Store -print0 2>/dev/null | LC_ALL=C sort -z | xargs -0 shasum -a 256 2>/dev/null | awk '{print $2, $1}' | iconv -f UTF-8-MAC -t UTF-8)
