65				return nil
66			}
67			rel = filepath.ToSlash(rel)
68			// Normalize to NFC so both sides of a sync agree on the key even when
69			// one filesystem stores NFD (macOS tar extraction does): APFS lookups
70			// are normalization-insensitive, so operating on the NFC name still
71			// reaches an NFD-stored file. Without this, unicode names ping-pong
72			// as "new" on both sides forever.
73			rel = norm.NFC.String(rel)
74	
75			// Skip paths with characters that would break shell quoting.
76			if strings.ContainsAny(rel, "'\n") {
77				fmt.Fprintf(os.Stderr, "scan: skip %q: contains single quote or newline\n", rel)
78				if d.IsDir() {
79					return filepath.SkipDir
80				}
81				return nil
82			}
83	
84			// Check excludes against every path segment.
85			if matchesExclude(rel, excludes) {
86				if d.IsDir() {
87					return filepath.SkipDir
88				}
89				return nil
90			}
91	
92			// Skip symlinks.
93			if d.Type()&fs.ModeSymlink != 0 {
94				symlinks++
95				return nil
96			}
97	
98			info, err := d.Info()
99			if err != nil {
100				fmt.Fprintf(os.Stderr, "scan: stat %s: %v\n", absPath, err)
101				return nil
102			}
103	
104			e := Entry{
105				Size:  info.Size(),
106				Mtime: info.ModTime().UnixNano(),
107				Mode:  uint32(info.Mode()),
108				IsDir: info.IsDir(),
109			}
110	
111			if hashFiles && !info.IsDir() {
112				if h, herr := hashFile(absPath); herr != nil {
113					fmt.Fprintf(os.Stderr, "scan: hash %s: %v\n", absPath, herr)
114				} else {
115					e.Hash = h
116				}
117			}
118	
119			entries[rel] = e
120			return nil
121		})
122	
123		return entries, symlinks, err
124	}
125	
126	// hashFile computes the sha256 digest of the file at path and returns it as a
127	// lowercase hex string.  The file is streamed so large files are not slurped
128	// into memory.
129	func hashFile(path string) (string, error) {
130		f, err := os.Open(path)
131		if err != nil {
132			return "", err
133		}
134		defer f.Close()
135		h := sha256.New()
136		if _, err := io.Copy(h, f); err != nil {
137			return "", err
138		}
139		return hex.EncodeToString(h.Sum(nil)), nil
140	}
141	
142	// matchesExclude returns true when rel matches any exclude pattern on any segment.
143	func matchesExclude(rel string, excludes []string) bool {
144		segments := strings.Split(rel, "/")
145		for _, seg := range segments {
146			for _, pat := range excludes {
147				if ok, _ := path.Match(pat, seg); ok {
148					return true
149				}
150			}
151		}
152		return false
153	}
154	
155	// CmdScan implements `caravan scan --json DIR [--exclude a,b,c] [--hash]`.
156	func CmdScan(args []string) int {
157		fs := flag.NewFlagSet("scan", flag.ContinueOnError)
158		fs.SetOutput(os.Stderr)
159		jsonOut := fs.Bool("json", false, "output directory state as JSON (required)")
160		excludeStr := fs.String("exclude", "", "comma-separated exclude patterns")
161		hashFiles := fs.Bool("hash", false, "compute sha256 hash for every regular file")
162	
163		positionals, err := cliargs.ParseAnywhere(fs, args)
164		if err != nil {
165			return 2
166		}
167	
168		if !*jsonOut {
169			fmt.Fprintln(os.Stderr, "scan: --json flag is required")
170			return 2
171		}
172	
173		if len(positionals) != 1 {
174			fmt.Fprintln(os.Stderr, "scan: expected exactly one DIR argument")
175			return 2
176		}
177	
178		var excludes []string
179		if *excludeStr != "" {
180			for _, e := range strings.Split(*excludeStr, ",") {
181				if e = strings.TrimSpace(e); e != "" {
182					excludes = append(excludes, e)
183				}
184			}
185		}
186	
187		dir := manifest.ExpandPath(positionals[0])
188	
189		result, symlinks, err := ScanDir(dir, excludes, *hashFiles)
190		if err != nil {
191			fmt.Fprintf(os.Stderr, "scan: %v\n", err)
192			return 1
193		}
194		if symlinks > 0 {
195			fmt.Fprintf(os.Stderr, "scan: skipped %d symlink(s)\n", symlinks)
196		}
197	
198		enc := json.NewEncoder(os.Stdout)
199		enc.SetIndent("", "  ")
200		if err := enc.Encode(ScanResult{Entries: result, Version: buildinfo.Version}); err != nil {
201			fmt.Fprintf(os.Stderr, "scan: encode: %v\n", err)
202			return 1
203		}
204		return 0
205	}

1	// Package manifest defines the caravan.toml schema, loading/saving, and path
2	// resolution shared by every command.
3	package manifest
4	
5	import (
6		"fmt"
7		"os"
8		"path/filepath"
9		"strings"
10	
11		"github.com/BurntSushi/toml"
12	)
13	
14	type Manifest struct {
15		Version   int       `toml:"version"`
16		Workspace Workspace `toml:"workspace"`
17		Repos     []Repo    `toml:"repos"`
18		Secrets   Secrets   `toml:"secrets"`
19		Toolchain Toolchain `toml:"toolchain"`
20		Sync      []Sync    `toml:"sync"`
21	
22		// Dir is the directory the manifest was loaded from (not serialized);
23		// relative paths like Secrets.File resolve against it.
24		Dir string `toml:"-"`
25	}
26	
27	type Workspace struct {
28		Root string `toml:"root"`
29	}
30	
31	type Repo struct {
32		Name   string `toml:"name"`
33		URL    string `toml:"url"`
34		Path   string `toml:"path,omitempty"`
35		Branch string `toml:"branch,omitempty"`
36		Sparse bool   `toml:"sparse,omitempty"`
37	}
38	
39	type Secrets struct {
40		File string `toml:"file,omitempty"`
41	}
42	
43	type Toolchain struct {
44		Mise bool `toml:"mise,omitempty"`
45	}
46	
47	type Sync struct {
48		Name     string   `toml:"name"`
49		Local    string   `toml:"local"`
50		Remote   string   `toml:"remote"`
51		Exclude  []string `toml:"exclude,omitempty"`
52		Checksum bool     `toml:"checksum,omitempty"`
53	}
54	
55	// DefaultExcludes are applied to every sync folder in addition to its own list.
56	var DefaultExcludes = []string{".git", "node_modules", ".DS_Store", "dist", "target", ".next", ".cache"}
57	
58	// ExpandPath expands a leading "~/" (or bare "~") to the user home directory.
59	func ExpandPath(s string) string {
60		if s == "~" {
61			h, err := os.UserHomeDir()
62			if err == nil {
63				return h
64			}
65		}
66		if strings.HasPrefix(s, "~/") {
67			h, err := os.UserHomeDir()
68			if err == nil {
69				return filepath.Join(h, s[2:])
70			}
71		}
72		return s
73	}
74	
75	// DefaultPath returns ~/.config/caravan/caravan.toml.
76	func DefaultPath() string {
77		return ExpandPath("~/.config/caravan/caravan.toml")
78	}
79	
80	// ResolvePath applies the resolution order: explicit flag > $CARAVAN_MANIFEST > default.
81	func ResolvePath(flagValue string) string {
82		if flagValue != "" {
83			return ExpandPath(flagValue)
84		}
85		if env := os.Getenv("CARAVAN_MANIFEST"); env != "" {
86			return ExpandPath(env)
87		}
88		return DefaultPath()
89	}
90	
91	func Load(path string) (*Manifest, error) {
92		var m Manifest
93		meta, err := toml.DecodeFile(path, &m)
94		if err != nil {
95			return nil, fmt.Errorf("loading manifest %s: %w", path, err)
96		}
97		if undec := meta.Undecoded(); len(undec) > 0 {
98			fmt.Fprintf(os.Stderr, "warning: unknown manifest keys: %v\n", undec)
99		}
100		abs, err := filepath.Abs(path)
101		if err != nil {
102			abs = path
103		}
104		m.Dir = filepath.Dir(abs)
105		if err := m.Validate(); err != nil {
106			return nil, fmt.Errorf("invalid manifest %s: %w", path, err)
107		}
108		return &m, nil
109	}
110	
111	func Save(path string, m *Manifest) error {
112		if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
113			return err
114		}
115		f, err := os.CreateTemp(filepath.Dir(path), ".caravan-toml-*")
116		if err != nil {
117			return err
118		}
119		defer os.Remove(f.Name())
120		enc := toml.NewEncoder(f)
121		enc.Indent = ""
122		if err := enc.Encode(m); err != nil {
123			f.Close()
124			return err
125		}
126		if err := f.Close(); err != nil {
127			return err
128		}
129		return os.Rename(f.Name(), path)
130	}
131	
132	func (m *Manifest) Validate() error {
133		seen := map[string]bool{}
134		for _, r := range m.Repos {
135			if r.Name == "" || r.URL == "" {
136				return fmt.Errorf("repo entries need name and url (got name=%q url=%q)", r.Name, r.URL)
137			}
138			if seen["repo:"+r.Name] {
139				return fmt.Errorf("duplicate repo name %q", r.Name)
140			}
141			seen["repo:"+r.Name] = true
142		}
143		for _, s := range m.Sync {
144			if s.Name == "" || s.Local == "" || s.Remote == "" {
145				return fmt.Errorf("sync entries need name, local, remote (got name=%q)", s.Name)
146			}
147			if seen["sync:"+s.Name] {
148				return fmt.Errorf("duplicate sync name %q", s.Name)
149			}
150			seen["sync:"+s.Name] = true
151		}
152		return nil
153	}
154	
155	// RepoDir returns the absolute directory for a repo.
156	func (m *Manifest) RepoDir(r Repo) string {
157		p := r.Path
158		if p == "" {
159			p = r.Name
160		}
161		if filepath.IsAbs(p) {
162			return p
163		}
164		return filepath.Join(ExpandPath(m.Workspace.Root), p)
165	}
166	
167	// SecretsPath returns the absolute path of the secrets file, or "" if unset.
168	func (m *Manifest) SecretsPath() string {
169		if m.Secrets.File == "" {
170			return ""
171		}
172		p := ExpandPath(m.Secrets.File)
173		if filepath.IsAbs(p) {
174			return p
175		}
176		return filepath.Join(m.Dir, p)
177	}
178	
179	// Excludes returns the effective exclude list for a sync entry.
180	func (s Sync) Excludes() []string {
181		out := append([]string{}, DefaultExcludes...)
182		for _, e := range s.Exclude {
183			dup := false
184			for _, d := range out {
185				if d == e {
186					dup = true
187					break
188				}
189			}
190			if !dup {
191				out = append(out, e)
192			}
193		}
194		return out
195	}

