1	package syncengine
2	
3	import (
4		"encoding/json"
5		"fmt"
6		"io"
7		"os"
8		"os/exec"
9		"path/filepath"
10		"runtime"
11		"strings"
12		"sync"
13	
14		"caravan/internal/buildinfo"
15	)
16	
17	// transportKind identifies the transfer mechanism.
18	type transportKind int
19	
20	const (
21		transportSSH   transportKind = iota
22		transportLocal               // local:<abs-path> — no ssh, direct FS ops
23	)
24	
25	// RemoteConn describes and operates on one side of a sync pair.
26	type RemoteConn struct {
27		Kind    transportKind
28		Host    string // SSH: user@host; Local: ""
29		Root    string // absolute-ish remote root path (may start with ~)
30	}
31	
32	// ParseRemote parses a remote spec into a RemoteConn.
33	//
34	//   - "local:<abs-path>"  → local transport, useful for mounted volumes and tests
35	//   - "user@host:path"    → SSH transport
36	func ParseRemote(spec string) (*RemoteConn, error) {
37		if strings.HasPrefix(spec, "local:") {
38			root := spec[len("local:"):]
39			if root == "" {
40				return nil, fmt.Errorf("remote spec %q: local: requires a path", spec)
41			}
42			return &RemoteConn{Kind: transportLocal, Root: root}, nil
43		}
44	
45		// Expect user@host:path or host:path
46		idx := strings.LastIndex(spec, ":")
47		if idx < 0 {
48			return nil, fmt.Errorf("remote spec %q: expected user@host:path or local:<path>", spec)
49		}
50		host := spec[:idx]
51		path := spec[idx+1:]
52		if host == "" || path == "" {
53			return nil, fmt.Errorf("remote spec %q: host and path must be non-empty", spec)
54		}
55		return &RemoteConn{Kind: transportSSH, Host: host, Root: path}, nil
56	}
57	
58	// --- Scan ---
59	
60	// Scan returns an Entry map for the remote root, applying excludes.
61	// When hashFiles is true, file content hashes are computed on the remote side.
62	// For SSH transport it invokes `caravan scan --json` on the remote; on scan
63	// failure that looks like a missing binary it attempts to bootstrap the remote
64	// and retries once.
65	func (r *RemoteConn) Scan(excludes []string, hashFiles bool) (map[string]Entry, error) {
66		switch r.Kind {
67		case transportLocal:
68			return r.scanLocal(excludes, hashFiles)
69		case transportSSH:
70			return r.scanSSH(excludes, hashFiles, true)
71		}
72		return nil, fmt.Errorf("unknown transport kind %d", r.Kind)
73	}
74	
75	func (r *RemoteConn) scanLocal(excludes []string, hashFiles bool) (map[string]Entry, error) {
76		if err := os.MkdirAll(r.Root, 0o755); err != nil {
77			return nil, fmt.Errorf("local remote mkdir %s: %w", r.Root, err)
78		}
79		entries, _, err := ScanDir(r.Root, excludes, hashFiles)
80		return entries, err
81	}
82	
83	func (r *RemoteConn) scanSSH(excludes []string, hashFiles bool, allowBootstrap bool) (map[string]Entry, error) {
84		excArg := strings.Join(excludes, ",")
85		remotePath := shellRemotePath(r.Root)
86		var cmd string
87		if excArg != "" {
88			cmd = fmt.Sprintf(`~/.local/bin/caravan scan --json --exclude %q %s`, excArg, remotePath)
89		} else {
90			cmd = fmt.Sprintf(`~/.local/bin/caravan scan --json %s`, remotePath)
91		}
92		if hashFiles {
93			cmd += " --hash"
94		}
95	
96		out, err := exec.Command("ssh", "-o", "BatchMode=yes", r.Host, cmd).Output()
97		if err != nil {
98			if allowBootstrap && looksLikeMissingBinary(err, out) {
99				fmt.Fprintf(os.Stderr, "caravan: remote binary not found on %s; bootstrapping…\n", r.Host)
100				if berr := r.bootstrap(); berr != nil {
101					return nil, fmt.Errorf("bootstrap %s: %w", r.Host, berr)
102				}
103				// Also ensure the remote root exists.
104				_ = r.mkdirSSH("")
105				return r.scanSSH(excludes, hashFiles, false)
106			}
107			// Try to create the remote root if it doesn't exist and retry once.
108			if allowBootstrap && looksLikeMissingDir(err, out) {
109				_ = r.mkdirSSH("")
110				return r.scanSSH(excludes, hashFiles, false)
111			}
112			return nil, fmt.Errorf("remote scan on %s: %w", r.Host, err)
113		}
114	
115		var result ScanResult
116		if err := json.Unmarshal(out, &result); err != nil {
117			return nil, fmt.Errorf("parse remote scan: %w", err)
118		}
119	
120		// Version handshake: if the remote binary is a different version, re-push
121		// it and rescan once (allowBootstrap guards against infinite recursion).
122		if result.Version != buildinfo.Version {
123			remoteVer := result.Version
124			if remoteVer == "" {
125				remoteVer = "pre-0.1.1"
126			}
127			fmt.Fprintf(os.Stderr, "remote caravan %s != local %s; updating…\n", remoteVer, buildinfo.Version)
128			if allowBootstrap {
129				if berr := r.bootstrap(); berr != nil {
130					fmt.Fprintf(os.Stderr, "caravan: version update failed: %v; proceeding\n", berr)
131				} else {
